      {"question_id":"ml_beg_002","type":"true_false","question":"A model with 99% training accuracy and 60% test accuracy is underfitting.","correct_answer":False,"explanation":"High training accuracy but low test accuracy indicates overfitting — the model memorised training data but failed to generalise. Underfitting is when both training and test accuracy are low.","difficulty_score":2,"time_seconds":30,"tags":["overfitting","underfitting","generalisation"],"prerequisites":["ml_beg_001"],"common_mistakes":["Confusing overfitting and underfitting"],"learning_resources":["https://developers.google.com/machine-learning/crash-course/generalization/peril-of-overfitting"],"real_world_context":"Overfitting on training data is the most common failure mode in ML model development."},
