      {"question_id":"ml_int_001","type":"mcq","question":"What does L2 regularisation (Ridge) do during model training?","options":["Randomly drops neurons","Adds the sum of squared weights to the loss, penalising large weights","Normalises input features","Reduces learning rate over time"],"correct_answer":1,"explanation":"L2 regularisation adds lambda * sum(w^2) to the loss function, penalising large weights and encouraging simpler models. This reduces overfitting by distributing weight across features instead of relying on a few large ones.","difficulty_score":5,"time_seconds":60,"tags":["regularisation","Ridge","overfitting","L2"],"prerequisites":["ml_beg_002"],"common_mistakes":["Confusing L1 (Lasso) and L2 (Ridge) effects"],"learning_resources":["https://developers.google.com/machine-learning/crash-course/regularization-for-simplicity/l2-regularization"],"real_world_context":"L2 regularisation is the default in most regression models through sklearn's Ridge class."},
      {"question_id":"ml_int_002","type":"scenario","question":"A binary classifier on a medical dataset achieves 98% accuracy, but all predictions are the negative class. What metric reveals this?","options":["Accuracy","F1-Score / Recall for positive class","AUC-ROC","Mean Squared Error"],"correct_answer":1,"explanation":"If 98% of samples are negative, predicting all negatives gives 98% accuracy but 0% recall on the positive class. F1-Score and Recall for the minority class expose this. Accuracy is misleading on imbalanced datasets.","difficulty_score":5,"time_seconds":75,"tags":["imbalanced_data","recall","F1_score","classification_metrics"],"prerequisites":["ml_beg_002"],"common_mistakes":["Using only accuracy for imbalanced classification tasks"],"learning_resources":["https://scikit-learn.org/stable/modules/model_evaluation.html"],"real_world_context":"Medical screening, fraud detection, and defect detection all have highly imbalanced classes."},
      {"question_id":"ml_int_003","type":"mcq","question":"What is feature importance in a Random Forest model?","options":["Number of features used","A measure of how much each feature contributes to reducing impurity across all trees","Correlation between features","Normalised feature values"],"correct_answer":1,"explanation":"Random Forest feature importance measures the average reduction in Gini impurity (or MSE) contributed by each feature across all trees. Higher importance = the feature is more useful for splitting nodes.","difficulty_score":5,"time_seconds":60,"tags":["random_forest","feature_importance","interpretability"],"prerequisites":["ml_int_001"],"common_mistakes":["Thinking feature importance equals correlation with the target"],"learning_resources":["https://scikit-learn.org/stable/auto_examples/ensemble/plot_forest_importances.html"],"real_world_context":"Feature importance is used to explain model decisions and reduce dimensionality."},
      {"question_id":"ml_int_004","type":"code_debugging","question":"A model trained on 2020 data deployed in 2024 shows degrading performance. What is this phenomenon?","options":["Overfitting","Data/concept drift","Underfitting","Label noise"],"correct_answer":1,"explanation":"Data drift occurs when the statistical distribution of input features changes over time. Concept drift occurs when the relationship between features and target changes. Both cause model performance to degrade in production after deployment.","difficulty_score":6,"time_seconds":60,"tags":["data_drift","concept_drift","MLOps","model_monitoring"],"prerequisites":["ml_int_002"],"common_mistakes":["Assuming a trained model stays accurate indefinitely"],"learning_resources":["https://www.evidentlyai.com/ml-in-production/data-drift"],"real_world_context":"Model monitoring for drift is a core MLOps practice to maintain production model quality."}
