      {"question_id":"ml_adv_001","type":"scenario","question":"A model has high bias. Which approach is MOST likely to help?","options":["Increase regularisation","Add more training data indefinitely","Use a more complex model or add features","Remove outliers from training data"],"correct_answer":2,"explanation":"High bias means the model is too simple to capture the underlying patterns (underfitting). A more complex model architecture (more parameters, higher polynomial degree) or richer feature engineering directly addresses high bias.","difficulty_score":7,"time_seconds":90,"tags":["bias_variance","underfitting","model_complexity"],"prerequisites":["ml_int_001","ml_int_002"],"common_mistakes":["Adding more data to fix a bias problem (helps variance, not bias)"],"learning_resources":["https://developers.google.com/machine-learning/crash-course/"],"real_world_context":"Bias-variance diagnosis determines whether to collect more data or change the model architecture."},
      {"question_id":"ml_adv_002","type":"mcq","question":"What is the primary purpose of SHAP values in ML interpretability?","options":["Speed up model training","Explain each feature's contribution to a specific prediction using game theory","Replace cross-validation","Regularise model weights"],"correct_answer":1,"explanation":"SHAP (SHapley Additive exPlanations) uses game-theoretic Shapley values to fairly attribute each feature's contribution to a specific model prediction. Unlike global feature importance, SHAP provides local per-prediction explanations.","difficulty_score":8,"time_seconds":120,"tags":["SHAP","interpretability","explainability","XAI"],"prerequisites":["ml_adv_001"],"common_mistakes":["Confusing SHAP with global feature importance"],"learning_resources":["https://shap.readthedocs.io/en/latest/"],"real_world_context":"SHAP is required for regulatory compliance (GDPR right to explanation) in financial AI models."}
